noncompliant:
int counter = 0;

// Noncompliant: sizeof with side effects (increment)
size_t size1 = sizeof(++counter);

// Noncompliant: function call with side effects
int getValue() {
    static int value = 0;
    return ++value;  // Side effect: modifies static variable
}
size_t size2 = sizeof(getValue());

// Noncompliant: assignment within sizeof
int x, y;
size_t size3 = sizeof(x = y);

// Noncompliant: compound assignment
int array[10];
size_t size4 = sizeof(array[counter++]);

compliant:
int counter = 0;
int array[10];

// Compliant: sizeof with type names
size_t size1 = sizeof(int);
size_t size2 = sizeof(double);

// Compliant: sizeof with variable names (no evaluation)
size_t size3 = sizeof(counter);
size_t size4 = sizeof(array);

// Compliant: sizeof with expressions without side effects
size_t size5 = sizeof(counter + 1);
size_t size6 = sizeof(array[0]);

// Compliant: using variables for side effects outside sizeof
counter++;
size_t size7 = sizeof(counter);
